let payload = {
  bookId: $('When Executed by Another Workflow').first().json.bookId,
  wordCount: 0,
  pageCount: 0,
  pdfUrl: `https://bestsellers-ai.s3.us-east-1.amazonaws.com/${$('Sanitize Title Filename1').first().json.filename}.pdf`,
  docxUrl: `https://bestsellers-ai.s3.us-east-1.amazonaws.com/${$('Sanitize Title Filename1').first().json.filename}.docx`,
  introduction: $('Generate Introduction1').first().json.output,
  conclusion: $('Generate Conclusion1').first().json.output,
  finalConsiderations: $('Generate Final_Considerations1').first().json.output,
  resourcesReferences: $('Generate Resources_References1').first().json.output,
  appendix: $('Generate Appendix1').first().json.output,
  glossary: $('Generate Glossary1').first().json.output,
  closure: $('Generate Closure1').first().json.output
};

const wordCount = (text) => text.trim().split(/\s+/).filter(Boolean).length;

function pageCount(texto, palavrasPorPagina = 247) {
  const palavras = texto.trim().split(/\s+/).length;
  return Math.ceil(palavras / palavrasPorPagina);
}

let book = { 
  chapters: $('HTTP Request3').first().json.chapters, 
  introduction: payload.introduction,
  conclusion: payload.conclusion,
  finalConsiderations: payload.finalConsiderations,
  resourcesReferences: payload.resourcesReferences,
  appendix: payload.appendix,
  glossary: payload.glossary,
  closure: payload.closure,
  wordCount: 0,
  pageCount: 0
}
const totalWords = wordCount(JSON.stringify(book));
const totalPages = pageCount(JSON.stringify(book));

payload.wordCount = totalWords;
payload.pageCount = totalPages;

return payload;

const sanitize = (str) => {
  return str
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // remove acentos
    .replace(/[^a-zA-Z0-9._-]+/g, "_")               // troca QUALQUER coisa não segura por _
    .replace(/_+/g, "_")                             // evita múltiplos __
    .replace(/^_+|_+$/g, "")                         // remove _ do início e fim
    .toLowerCase();
};

let title = sanitize($input.first().json.title);
let filename = `Final_${title}_v1`;
return {filename};
